blocks.body:
{
    "level": "A1–A2",
    "intro": "]W tym temacie dowiesz się jak tworzy się <strong>rzeczowniki w liczbie mnogiej</strong> w języku angielskim – główne zasady i wyjątki.",
    "rules": [
        {
            "label": "+ S",
            "color": "emerald",
            "text": "<strong>Dodawanie -s</strong> – główna zasada:",
            "example": "cat → koty, książka → książki, pies → psy"
        },
        {
            "label": "+ ES",
            "color": "blue",
            "text": "<strong>Dodawanie -es</strong> — po s, x, z, ch, sh:",
            "example": "pudełko → pudełka, autobusy → autobusy, zegarek → zegarki"
        },
        {
            "label": "Y → IES",
            "color": "amber",
            "text": "<strong>Zastąpienie y przez ies</strong> — po spółgłosce:",
            "example": "dziecko → dzieci, miasto → miasta, impreza → imprezy"
        }
    ]
}

{
    "title": "1. Główne sposoby tworzenia liczby mnogiej",
    "intro": "Istnieją trzy główne zasady tworzenia liczby mnogiej rzeczowników angielskich:",
    "items": [
        {
            "label": "+ S",
            "title": "Dodaj -s",
            "subtitle": "Większość rzeczowników to kot → koty, książka → książki"
        },
        {
            "label": "+ ES",
            "title": "Dodaj -es",
            "subtitle": "Po s, x, z, ch, sh — pudełko → skrzynki, autobus → autobusy"
        },
        {
            "label": "Y → IES",
            "title": "Y zmień na IES",
            "subtitle": "Po spółgłosce — dziecko → dzieci, miasto → miasta"
        }
    ]
}

{
    "title": "2. Zasada 1: Dodawanie -s",
    "sections": [
        {
            "label": "Zasada podstawowa",
            "color": "emerald",
            "description": "Większość rzeczowników tworzy liczbę mnogą poprzez proste <strong>dodanie -s</strong>.",
            "examples": [
                {
                    "en": "kot → koty",
                    "ua": "kot → koty"
                },
                {
                    "en": "pies → psy",
                    "ua": "pies → psy"
                },
                {
                    "en": "książka → książki",
                    "ua": "książka → książki"
                },
                {
                    "en": "stół → stoły",
                    "ua": "tabela → tabele"
                }
            ]
        },
        {
            "label": "Po samogłoskach",
            "color": "sky",
            "description": "Po literach samogłosek (a, e, i, o, u) po prostu dodajemy <strong>-s</strong>.",
            "examples": [
                {
                    "en": "pszczoła → pszczoły",
                    "ua": "pszczoła → pszczoły"
                },
                {
                    "en": "drzewo → drzewa",
                    "ua": "drzewo → drzewa"
                },
                {
                    "en": "but → buty",
                    "ua": "but → buty"
                },
                {
                    "en": "zoo → ogrody zoologiczne",
                    "ua": "zoo → zoos"
                }
            ]
        },
        {
            "label": "Wymowa",
            "color": "amber",
            "description": "Koniec <strong>-s</strong> wymawia się jako [s], [z] lub [ɪz] w zależności od poprzedzającego dźwięku.",
            "examples": [
                {
                    "en": "books [bʊks] to dźwięk [s]",
                    "ua": " po bezdźwięcznym spółgłoski"
                },
                {
                    "en": "psy [dɒɡz] to dźwięk [z]",
                    "ua": " po dźwięcznych spółgłoskach i samogłoskach"
                },
                {
                    "en": "busach [ˈbʌsɪz] - dźwięk [ɪz]",
                    "ua": "po s, z, sh, ch, x"
                }
            ],
            "note": "📌 Dzieje się to automatycznie – nie jest wymagana żadna specjalna nauka!"
        }
    ]
}

{
    "title": "3. Zasada 2: Dodawanie -es",
    "sections": [
        {
            "label": "Po s, ss, x, z",
            "color": "blue",
            "description": "Jeśli rzeczownik kończy się na <strong>s, ss, x, z</strong>, dodaj <strong>-es</strong>.",
            "examples": [
                {
                    "en": "bus → autobusy",
                    "ua": "autobus → autobusy"
                },
                {
                    "en": "szkło → okulary",
                    "ua": "szkło → okulary"
                },
                {
                    "en": "pudełko → pudełka",
                    "ua": "pudełko → pudełka"
                },
                {
                    "en": "quiz → quizy",
                    "ua": "test → testy"
                }
            ]
        },
        {
            "label": "Po ch, sh",
            "color": "sky",
            "description": "Jeśli rzeczownik kończy się na <strong>ch lub sh</strong>, dodajemy również <strong>-es</strong>.",
            "examples": [
                {
                    "en": "oglądaj → zegarki",
                    "ua": "zegar → zegarki"
                },
                {
                    "en": "kościół → kościoły",
                    "ua": "kościół → kościoły"
                },
                {
                    "en": "naczynie → naczynia",
                    "ua": "talerz → talerze"
                },
                {
                    "en": "pędzel → pędzle",
                    "ua": "pędzel → pędzle"
                }
            ]
        },
        {
            "label": "Dlaczego -es?",
            "color": "purple",
            "description": "Dodanie <strong>-es</strong> ułatwia wymowę po syczących i gwiżdżących dźwiękach.",
            "examples": [
                {
                    "en": "box + s = pudełka ✗ (trudne do wymówienia)",
                    "ua": "niepoprawne"
                },
                {
                    "en": "box + es = pudełka ✓ [ˈbɒksɪz]",
                    "ua": "poprawne"
                }
            ],
            "note": "📌 Dodaje to sylabę ułatwiającą wymowę!"
        }
    ]
}

{
    "title": "4. Zasada 3: Y → IES",
    "sections": [
        {
            "label": "Spółgłoska + Y",
            "color": "amber",
            "description": "Jeśli <strong>y</strong> jest poprzedzone <strong>spółgłoską</strong>, zamień <strong>y na ies</strong>.",
            "examples": [
                {
                    "en": "dziecko → dzieci",
                    "ua": "dziecko → dzieci"
                },
                {
                    "en": "miasto → miasta",
                    "ua": "miasto → miasta"
                },
                {
                    "en": "impreza → imprezy",
                    "ua": "impreza → imprezy"
                },
                {
                    "en": "kraj → kraje",
                    "ua": "kraj → kraje"
                }
            ]
        },
        {
            "label": "Głos + y dni",
            "color": "emerald",
            "description": "Якщо перед <strong>y</strong> стоїть <strong>голосна</strong> (a, e, i, o, u), просто додаємо <strong>-s</strong>.",
            "examples": [
                {
                    "en": "boy → boys",
                    "ua": "хлопчик → хлопчики"
                },
                {
                    "en": "day → days",
                    "ua": "день → дні"
                },
                {
                    "en": "klawisz → klawisze",
                    "ua": "klawisz → klawisze"
                },
                {
                    "en": "zabawka → zabawki",
                    "ua": "zabawka → zabawki"
                }
            ]
        },
        {
            "label": "Jak zapamiętać?",
            "color": "sky",
            "description": "Łatwy sposób na zapamiętanie reguły:",
            "examples": [
                {
                    "en": "Spółgłoska + y → ies",
                    "ua": "dziecko → dzieci"
                },
                {
                    "en": "samogłoska + y → ys",
                    "ua": "chłopiec → chłopcy"
                }
            ],
            "note": "]📌 Spójrz na literę PRZED y!"
        }
    ]
}

{
    "title": "5. Rzeczowniki na -o",
    "sections": [
        {
            "label": "Spółgłoska + O → OES",
            "color": "purple",
            "description": "Niektóre rzeczowniki na <strong>-o</strong> (po spółgłosce) dodają <strong>-es</strong>.",
            "examples": [
                {
                    "en": "pomidor → pomidory",
                    "ua": "pomidor → pomidory"
                },
                {
                    "en": "ziemniak → ziemniaki",
                    "ua": "ziemniak → ziemniaki"
                },
                {
                    "en": "bohater → bohaterowie",
                    "ua": "bohater → bohaterowie"
                },
                {
                    "en": "echo → echa",
                    "ua": "echo → echo[[CODX_SEG_20]]]Samogłoska + O → OS"
                }
            ]
        },
        {
            "label": "Голосна + O → OS",
            "color": "emerald",
            "description": "Jeśli <strong>-o</strong> jest poprzedzone samogłoską, po prostu dodaj <strong>-s</strong>.",
            "examples": [
                {
                    "en": "radio → radia",
                    "ua": "radio → radio"
                },
                {
                    "en": "wideo → filmy",
                    "ua": "filmy → filmy"
                },
                {
                    "en": "zoo → ogrody zoologiczne",
                    "ua": "zoo → ogrody zoologiczne"
                },
                {
                    "en": "studio → studia",
                    "ua": "studio → studia"
                }
            ]
        },
        {
            "label": "Muzyka i kawałki → OS",
            "color": "sky",
            "description": "Terminy muzyczne i skróty zawsze z <strong>-s</strong>.",
            "examples": [
                {
                    "en": "fortepian → fortepiany",
                    "ua": "fortepian → fortepian"
                },
                {
                    "en": "zdjęcie → zdjęcia",
                    "ua": "zdjęcie → zdjęcie"
                },
                {
                    "en": "kil → kilogramy",
                    "ua": "kilogramy → kilogramy"
                }
            ],
            "note": "⚠️ Należy pamiętać o wyjątkach!"
        }
    ]
}

{
    "title": "6. Rzeczowniki z -f/-fe → VES",
    "sections": [
        {
            "label": "F/FE → VES",
            "color": "rose",
            "description": "Wiele rzeczowników z <strong>-f</strong> lub <strong>-fe</strong> zmieniają końcówkę na <strong>-ves</strong>.",
            "examples": [
                {
                    "en": "nóż → noże",
                    "ua": "nóż → noże"
                },
                {
                    "en": "żona → żony",
                    "ua": "żona → żony"
                },
                {
                    "en": "liść → liście",
                    "ua": "liść → liście"
                },
                {
                    "en": "wilk → wilki",
                    "ua": "wilk → wilki"
                }
            ]
        },
        {
            "label": "Więcej przykładów",
            "color": "amber",
            "description": "Inne rzeczowniki pospolite z tą zmianą:",
            "examples": [
                {
                    "en": "half → halfves",
                    "ua": "half → połówki"
                },
                {
                    "en": "półka → półki",
                    "ua": "półka → półki"
                },
                {
                    "en": "złodziej → złodzieje",
                    "ua": "złodzieje → złodzieje"
                },
                {
                    "en": "życie → życie",
                    "ua": "życie → życie (lm.)"
                }
            ]
        },
        {
            "label": "Wyjątki: tylko + S",
            "color": "sky",
            "description": "Ale niektóre rzeczowniki z -f po prostu dodają <strong>-s</strong>:",
            "examples": [
                {
                    "en": "dach → dachy",
                    "ua": "dah → dachy"
                },
                {
                    "en": "szef → wodzowie",
                    "ua": "przywódca → przywódcy"
                },
                {
                    "en": "przekonanie → przekonania",
                    "ua": "przekonanie → przekonania"
                }
            ],
            "note": "📌 Te wyjątki muszą być zapamiętany!"
        }
    ]
}

{
    "title": "7. Nieregularna liczba mnoga",
    "sections": [
        {
            "label": "Zmiana samogłoski",
            "color": "purple",
            "description": "Niektóre rzeczowniki zmieniają <strong>samogłoskę wewnętrzną</strong>.",
            "examples": [
                {
                    "en": "mężczyzna → mężczyźni",
                    "ua": "mężczyzna → mężczyźni"
                },
                {
                    "en": "kobieta → kobiety",
                    "ua": "kobieta → kobiety"
                },
                {
                    "en": "stopa → stopy",
                    "ua": "stopa → stopy"
                },
                {
                    "en": "ząb → zęby",
                    "ua": "ząb → zęby"
                }
            ]
        },
        {
            "label": "Całkowicie inna forma",
            "color": "rose",
            "description": "Niektóre rzeczowniki mają <strong>całkowicie różne</strong> formy liczby mnogiej.",
            "examples": [
                {
                    "en": "dziecko → dzieci",
                    "ua": "dziecko → dzieci"
                },
                {
                    "en": "osoba → ludzie",
                    "ua": "mężczyzna → ludzie"
                },
                {
                    "en": "mysz → myszy",
                    "ua": "mysz → myszy"
                },
                {
                    "en": "gęś → gęsi",
                    "ua": "gęś → gęsi"
                }
            ]
        },
        {
            "label": "ta sama forma",
            "color": "emerald",
            "description": "niektóre rzeczowniki <strong>nie zmieniają się</strong> w liczbie mnogiej.",
            "examples": [
                {
                    "en": "owca → owca",
                    "ua": "owca → owca"
                },
                {
                    "en": "ryba → ryba",
                    "ua": "ryba → ryba"
                },
                {
                    "en": "jeleń → jeleń",
                    "ua": "jeleń → jeleń"
                },
                {
                    "en": "seria → seria",
                    "ua": "seria → seria"
                }
            ],
            "note": "📌 Ryby mogą być rybami, jeśli łowią różne gatunki."
        }
    ]
}

{
    "title": "8. Tabela porównawcza reguł",
    "intro": "Podstawowe zasady tworzenia liczby mnogiej:",
    "rows": [
        {
            "en": "Większość rzeczowników",
            "ua": "Większość rzeczowników",
            "note": "+ s: kot → koty, książka → książki"
        },
        {
            "en": "Po s, x, z, ch, sh",
            "ua": "Po s, x, z, ch, sh",
            "note": "+ es: pudełko → pudełka, autobus → autobusy"
        },
        {
            "en": "Spółgłoska + y",
            "ua": "Spółgłoska + y",
            "note": "y → ies: dziecko → dzieci, miasto → miasta"
        },
        {
            "en": "samogłoska + y",
            "ua": "samogłoska + y",
            "note": "+ s: chłopiec → chłopcy, dzień → dni"
        },
        {
            "en": "f / fe",
            "ua": "Zakończenie f/fe",
            "note": "f/fe → ves: nóż → noże, liść → liście"
        },
        {
            "en": "Nieregularny",
            "ua": "Nieregularny",
            "note": "mężczyzna → mężczyźni, dzieci → dzieci, owce → owce"
        }
    ],
    "warning": "📌 Nieregularne formy liczby mnogiej należy badać poprzez serce!"
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zapomnij o -es po sybilantach.",
            "wrong": "dwa pudełka, trzy magistrale",
            "right": " ✅ <span class="font-mono">dwa pudełka, trzy autobusy</span>[[[CODX_10]]]Błąd 2"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Bez zmian na ies.",
            "wrong": "dzieci, miasta",
            "right": "​​​​ <span class="font-mono">dzieci, miasta</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zamień y na ies po samogłosce.",
            "wrong": "chłopcy, chłopcy",
            "right": "​​​​​​​​ stopy</span>"
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Правильна форма неправильних іменників.",
            "wrong": "childs, mans, foots",
            "right": "✅ <span class="font-mono">children, men, feet</span>"
        }
    ]
}

{
    "title": "11. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz poprawną formę liczby mnogiej",
    "select_intro": "Wybierz poprawną formę liczby mnogiej dla każdego rzeczownika.",
    "selects": [
        {
            "label": "kot → (cats / cates / caties)",
            "prompt": "Co to jest liczba mnoga?"
        },
        {
            "label": "pudełko → (boxy / pudełka / boxies)",
            "prompt": "Co to jest liczba mnoga?"
        },
        {
            "label": "dziecko → (dziecko / niemowlęta / babes)",
            "prompt": "Co to jest liczba mnoga?"
        },
        {
            "label": "chłopiec → (chłopcy / chłopcy / chłopcy)",
            "prompt": "Co to jest liczba mnoga?"
        }
    ],
    "options": [
        "Pierwsza opcja",
        "Druga opcja",
        "Trzecia opcja"
    ],
    "input_title": "Ćwiczenie 2. Zapisz liczbę mnogą",
    "input_intro": "Wpisz dla nich poprawną formę liczby mnogiej rzeczowniki.",
    "inputs": [
        {
            "before": "dziecko → ",
            "after": ""
        },
        {
            "before": "nóż → ",
            "after": ""
        },
        {
            "before": "ziemniak → ",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w liczbie mnogiej formularz.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Mam dwójkę dzieci.",
            "example_target": "Mam dwójkę dzieci."
        },
        {
            "original": "1. Na stole znajdują się trzy pola.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Zeszłego lata odwiedziłem pięć miast.",
            "placeholder": "Napraw błąd"
        }
    ]
}

{
    "title": "Inne strony z kategorii Rzeczowniki, artykuły i liczba",
    "items": [
        {
            "label": "Rzeczowniki w liczbie mnogiej – Rzeczowniki w liczbie mnogiej (bieżące)",
            "current": true
        },
        {
            "label": "Artykuły A/An/The – Artykuły",
            "current": false
        },
        {
            "label": "Policzalne a Niepoliczalne – Policzalne/niepoliczalne",
            "current": false
        },
        {
            "label": "Niektóre/Dowolne – Ilość",
            "current": false
        }
    ]
}
